INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '27af3511-699d-43b9-9ac2-27ef66cbf7c6',
  '00000000-0000-0000-0000-000000000001',
  $escape$seaborn + Pandas Fundamentals — How DataFrame Structure Controls Your Plots$escape$,
  $escape$seaborn is DataFrame-native. Every plot function reads column names directly as axis labels, hue groups, and facets — meaning your Pandas structure *is* your plot specification. seaborn expects tidy (long-format) data: one observation per row, one variable per column. If your DataFrame is wide, `df.melt(id_vars, value_vars)` reshapes it before passing to `sns.lineplot` or `sns.boxplot`. The `hue`, `col`, and `row` parameters in `sns.FacetGrid` map directly to categorical columns — so a `groupby` you'd do manually in Pandas is handled declaratively by seaborn when your data is structured correctly. For multi-dataset plots, use `pd.merge()` to join before plotting rather than layering separate `ax.plot()` calls — seaborn can then handle legend and color mapping automatically. Index-aware selection (`df.loc[df['category'] == 'A']`) lets you pass clean subsets into `data=` without mutating the source DataFrame. Master `.melt()`, `.merge()`, and categorical dtypes (`pd.Categorical`) and seaborn's defaults — axis ordering, hue palettes, legend entries — will just work.$escape$,
  $escape$import seaborn as sns
import pandas as pd

# Wide → long with melt before plotting
df_wide = pd.DataFrame({'model': ['A', 'B'], 'train_acc': [0.91, 0.87], 'val_acc': [0.88, 0.85]})
df_long = df_wide.melt(id_vars='model', var_name='split', value_name='accuracy')
sns.barplot(data=df_long, x='model', y='accuracy', hue='split')

# Categorical dtype controls axis order
df_long['split'] = pd.Categorical(df_long['split'], categories=['train_acc', 'val_acc'], ordered=True)

# Merge two sources, let seaborn handle grouping
metrics = pd.merge(df_long, pd.DataFrame({'model': ['A', 'B'], 'params_M': [7, 13]}), on='model')
sns.scatterplot(data=metrics, x='params_M', y='accuracy', hue='split', style='model')$escape$,
