INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'b83a1e69-16e8-4d11-beb0-5c4a6be0824c',
  '00000000-0000-0000-0000-000000000001',
  $escape$seaborn — Visually Auditing Feature Engineering Choices Before They Hit Your Pipeline$escape$,
  $escape$Feature engineering lives or dies by signal quality — seaborn makes it fast to audit each decision before it reaches your model. After encoding categoricals with LabelEncoder or pd.Categorical codes, pipe the result into `sns.heatmap(df.corr(), annot=True, cmap="coolwarm", center=0)` to instantly see whether the encoding preserves ordinal signal or introduces noise against your target. For binning, pair `pd.cut` with `sns.histplot(df, x="age_bin", hue="target", multiple="stack")` — misaligned bin boundaries collapse class separation and show up immediately as uniform bar ratios. Scaling artifacts surface in `sns.boxplot(data=df[["fare", "log_fare"]])` side-by-side: skew reduction is visible in seconds without summary stats. Interaction features are the hardest to justify; `sns.pairplot(df, hue="target", diag_kind="kde", plot_kws={"alpha": 0.4})` surfaces pairwise separability across all candidate features at once. Use `sns.FacetGrid` to stress-test a candidate interaction (e.g. `fare_per_class`) across demographic strata before committing it to your sklearn Pipeline.$escape$,
  $escape$import seaborn as sns
import pandas as pd
import numpy as np
from sklearn.preprocessing import LabelEncoder

df = sns.load_dataset("titanic").dropna(subset=["age", "fare"])
df["sex_enc"] = LabelEncoder().fit_transform(df["sex"])
df["class_enc"] = df["pclass"].astype("category").cat.codes
df["age_bin"] = pd.cut(df["age"], bins=4, labels=False)
df["log_fare"] = np.log1p(df["fare"])

# 1. Post-encoding correlation audit
sns.heatmap(df[["survived","sex_enc","class_enc","age_bin","log_fare"]].corr(),
            annot=True, cmap="coolwarm", center=0)

# 2. Interaction feature separability
sns.pairplot(df[["survived","log_fare","age_bin","sex_enc"]],
             hue="survived", diag_kind="kde", plot_kws={"alpha": 0.4})$escape$,
  $escape$python$escape$,
