INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '6bfaf0a9-d2c1-4fdf-95e3-15ddb8885772',
  '00000000-0000-0000-0000-000000000001',
  $escape$Seaborn + Matplotlib Axes API — Publication-Quality Charts with Full Control$escape$,
  $escape$Seaborn plots return Axes objects, giving you direct access to Matplotlib's full customization API. Every seaborn function accepts an `ax` parameter — pass a pre-created Axes to compose multi-panel figures without fighting the library. Use `plt.subplots()` to build the grid first, then hand each Axes to seaborn. After plotting, call methods directly on the returned Axes: `ax.set_title()`, `ax.set_xlabel()`, `ax.tick_params()`, `ax.spines['top'].set_visible(False)`. For publication quality, strip the top and right spines — seaborn's `despine()` does this in one call and accepts `ax=` for targeted panels. Set figure dimensions upfront via `fig, axes = plt.subplots(1, 2, figsize=(10, 4))` rather than resizing after the fact. Use `fig.tight_layout()` or `fig.savefig('chart.pdf', bbox_inches='tight', dpi=300)` for clean exports. Avoid `plt.figure()` after seaborn calls — it creates a new figure instead of modifying the existing one. The Axes-first pattern keeps seaborn's statistical abstractions while giving you pixel-level Matplotlib control.$escape$,
  $escape$import seaborn as sns
import matplotlib.pyplot as plt

tips = sns.load_dataset('tips')

fig, axes = plt.subplots(1, 2, figsize=(11, 4))

sns.violinplot(data=tips, x='day', y='total_bill', hue='sex', ax=axes[0])
axes[0].set_title('Bill Distribution by Day')
axes[0].set_xlabel('')
sns.despine(ax=axes[0])

sns.regplot(data=tips, x='total_bill', y='tip', ax=axes[1], scatter_kws={'alpha': 0.4})
axes[1].set_title('Tip vs Bill')
sns.despine(ax=axes[1])

fig.tight_layout()
fig.savefig('publication.pdf', bbox_inches='tight', dpi=300)$escape$,
  $escape$python$escape$,
