INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'ea9e6ba5-095c-4f11-bd23-89ee961c17d5',
  '00000000-0000-0000-0000-000000000001',
  $escape$seaborn + Jupyter — Parameterized Notebooks for Reproducible EDA$escape$,
  $escape$Hardcoded dataset paths and inline style configs are the enemy of reproducible seaborn workflows. Use Papermill to parameterize your notebooks: tag a cell with `parameters` and inject values at runtime — dataset path, `palette`, `hue` column, even `figure.figsize`. Pair this with `sns.set_theme()` at the top of every notebook so all downstream plots inherit a consistent style without repeated calls to `axes_style()` or `plotting_context()`.

For reproducibility, pin your seaborn version in a `requirements.txt` and call `sns.reset_defaults()` before `sns.set_theme()` to clear any ambient state from previous cells. Store `FacetGrid` or `PairGrid` objects — not just figures — so consumers can iterate `.axes_dict` or call `.map()` again with different encodings without re-running the full pipeline.

Use `%matplotlib inline` over `%matplotlib notebook` for static snapshots in CI; `savefig()` with `bbox_inches='tight'` ensures seaborn's legends aren't clipped in exported PNGs. Structure cells as: imports → theme → data load → transforms → plots → export. Never mix transform logic inside a plot cell.$escape$,
  $escape$# parameters cell (tag this in Jupyter for Papermill injection)
dataset_path = "data/metrics.csv"
palette = "mako"
hue_col = "model_type"

import seaborn as sns
import pandas as pd
import matplotlib.pyplot as plt

sns.reset_defaults()
sns.set_theme(style="whitegrid", palette=palette, rc={"figure.figsize": (10, 6)})

df = pd.read_csv(dataset_path)

g = sns.FacetGrid(df, col="split", hue=hue_col, palette=palette)
g.map(sns.kdeplot, "loss", fill=True, alpha=0.5)
g.add_legend()

g.savefig("output/loss_distribution.png", bbox_inches="tight")$escape$,
  $escape$python$escape$,
