INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'e4e8821b-776f-4d07-983c-2c9420d51173',
  '00000000-0000-0000-0000-000000000001',
  $escape$seaborn lineplot — Killing the Bootstrap CI Bottleneck on Large Datasets$escape$,
  $escape$When you call sns.lineplot() on a DataFrame with tens of thousands of rows, seaborn silently runs 1000 bootstrap iterations to compute 95% confidence intervals — even if you never look at them. On a 100k-row dataset grouped by 5 hue levels, that's 5 million resamples just to draw a shaded band. Set errorbar=None to skip CI entirely, or errorbar='sd' for a single-pass standard deviation instead. For scatter plots with dense point clouds, pass rasterized=True to collapse overlapping markers into a bitmap layer — this cuts matplotlib render time and output file size dramatically without losing visual fidelity. When your DataFrame has many columns, slice before plotting: pass data=df[['x_col', 'y_col', 'hue_col']] so seaborn doesn't carry unused memory through its internal groupby pipeline. For faceted plots via sns.FacetGrid, pre-aggregate with df.groupby().agg() outside the grid — map_dataframe re-runs aggregation per facet otherwise. These three changes — dropping bootstrap CI, rasterizing dense plots, and column-slicing inputs — can reduce seaborn plotting time by 10–40x on production-scale DataFrames.$escape$,
  $escape$import seaborn as sns
import pandas as pd

df = pd.read_parquet("events.parquet")  # 500k rows

# Slice to only needed columns — seaborn's groupby carries full df otherwise
plot_df = df[["timestamp", "latency_ms", "region"]]

# errorbar=None skips 1000-iteration bootstrap — ~40x faster on large groups
ax = sns.lineplot(
    data=plot_df,
    x="timestamp",
    y="latency_ms",
    hue="region",
    errorbar=None,
)

# rasterized=True renders dense scatter as bitmap, cuts SVG/PDF size 10x
sns.scatterplot(
    data=plot_df, x="timestamp", y="latency_ms",
    rasterized=True, ax=ax
)$escape$,
  $escape$python$escape$,
