INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'bd3f46c4-0983-4afd-9eb4-7033bb3d1fca',
  '00000000-0000-0000-0000-000000000001',
  $escape$Seaborn Time Series — Visualizing Rolling Windows, Lag Features, and Seasonality$escape$,
  $escape$Seaborn doesn't do the time series math — pandas does — but it's your sharpest tool for revealing what that math uncovers. Use `lineplot()` with `estimator=None` to plot raw signals without aggregation collapsing your variance. For rolling windows, compute a 7-day rolling mean in pandas, then overlay it on the raw series using a second `lineplot()` call on the same `ax`, exploiting Seaborn's `hue` parameter to distinguish window sizes visually. Lag features expose autocorrelation: construct `df['lag_1'] = df['value'].shift(1)` then drop into `scatterplot(x='lag_1', y='value', data=df)` — diagonal clustering signals strong autocorrelation. For seasonality, `FacetGrid` is your weapon: set `col='month'` or `row='day_of_week'` to decompose seasonal patterns across subplots without a single loop. Pair with `lineplot(estimator='mean', errorbar='sd')` per facet to see both the seasonal trend and its variance envelope simultaneously. Always set `palette='flare'` for temporal ordering — perceptually sequential, not misleading.$escape$,
  $escape$import seaborn as sns
import pandas as pd
import matplotlib.pyplot as plt

df['rolling_7'] = df['value'].rolling(7).mean()
df['lag_1'] = df['value'].shift(1)
df['month'] = df['date'].dt.month

fig, axes = plt.subplots(1, 2, figsize=(14, 5))

# Raw + rolling overlay
sns.lineplot(data=df, x='date', y='value', alpha=0.4, ax=axes[0], label='raw')
sns.lineplot(data=df, x='date', y='rolling_7', ax=axes[0], label='7d rolling')

# Lag feature autocorrelation
sns.scatterplot(data=df, x='lag_1', y='value', alpha=0.3, ax=axes[1])

# Seasonality via FacetGrid
g = sns.FacetGrid(df, col='month', col_wrap=4)
g.map_dataframe(sns.lineplot, x='day', y='value', estimator='mean', errorbar='sd')
plt.show()$escape$,
  $escape$python$escape$,
