INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'f9ecfdc0-a2e7-4445-9008-a3f19ac61045',
  '00000000-0000-0000-0000-000000000001',
  $escape$seaborn Reproducibility — Seeds, Pinned Envs, and Script Exports That Actually Work$escape$,
  $escape$seaborn wraps matplotlib and often delegates randomness to numpy and scipy — so `np.random.seed()` alone won't cover you. When using `sns.stripplot`, `sns.swarmplot`, or `sns.clustermap` (which runs scipy's linkage), set seeds at every layer: `np.random.seed(42)` before plotting and `random.seed(42)` for Python-level shuffles. For `sns.pairplot` with KDE diagonals, seaborn calls `scipy.stats.gaussian_kde` internally — results are deterministic given the data, but float precision can drift across scipy versions, so pin `scipy`, `seaborn`, `matplotlib`, and `numpy` together in `requirements.txt`.

Notebook-to-script conversion is where reproducibility breaks. `sns.set_theme()` state persists across cells but not across script runs unless called explicitly at the top. Export notebooks with `jupyter nbconvert --to script`, then audit for any cell-order-dependent `rcParams` mutations. Wrap your full plot pipeline in a function with an explicit `seed` parameter so callers control randomness. Use `matplotlib.pyplot.close('all')` between runs to prevent style bleed from cached figure state.$escape$,
  $escape$import random
import numpy as np
import seaborn as sns
import matplotlib.pyplot as plt
from sklearn.datasets import load_iris

def plot_iris_swarm(seed: int = 42) -> None:
    random.seed(seed)
    np.random.seed(seed)

    sns.set_theme(style="whitegrid")  # explicit — don't rely on notebook state
    df = load_iris(as_frame=True).frame
    df.columns = [*load_iris().feature_names, "species"]

    plt.figure(figsize=(8, 5))
    sns.swarmplot(data=df, x="species", y="sepal length (cm)", size=4)
    plt.savefig(f"swarm_seed{seed}.png", dpi=150)
    plt.close("all")  # prevent rcParams bleed on repeated calls

plot_iris_swarm(seed=42)$escape$,
  $escape$python$escape$,
