INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'e32324a7-837a-43d8-a308-6c39c837db5c',
  '00000000-0000-0000-0000-000000000001',
  $escape$seaborn Data Versioning — Embedding Dataset Lineage Directly Into Your Plots$escape$,
  $escape$When you regenerate a seaborn plot weeks later, how do you know which dataset version produced it? Without versioning discipline, EDA artifacts become orphaned — sharp-looking charts with no reproducible lineage.

The pattern: hash your DataFrame at plot time and embed that fingerprint directly into the seaborn figure — in the title, as a footnote via `fig.text()`, and in the output filename. `pd.util.hash_pandas_object()` produces row-level hashes; taking MD5 over those values yields an 8-char digest that changes the moment any row does.

Use `ax.set_title()` to surface both a semantic version tag and the hash prominently. Encode both in the saved filename so directory listings alone tell you the lineage without opening a file.

Pair this with DVC or MLflow: log the seaborn figure as an artifact alongside `dataset_hash` as a run parameter. Now your training run, its validation plots — seaborn confusion matrices, residual plots, pairplots — and the exact dataset state are traceable through a single hash. You can diff two seaborn plots by comparing hashes before visually inspecting them, catching silent data drift before it misleads model evaluation.$escape$,
  $escape$import hashlib
import pandas as pd
import seaborn as sns
import matplotlib.pyplot as plt

def versioned_plot(df: pd.DataFrame, version: str) -> str:
    digest = hashlib.md5(
        pd.util.hash_pandas_object(df, index=True).values
    ).hexdigest()[:8]

    fig, ax = plt.subplots(figsize=(8, 5))
    sns.histplot(data=df, x="tip", hue="day", multiple="stack", ax=ax)
    ax.set_title(f"Tip Distribution — v{version} [{digest}]")
    fig.text(0.99, 0.01, f"dataset_hash={digest}", ha="right", fontsize=7, color="gray")

    fig.savefig(f"plots/tip_dist_v{version}_{digest}.png", dpi=150, bbox_inches="tight")
    plt.close(fig)
    return digest

tips = sns.load_dataset("tips")
print(versioned_plot(tips, "1.2.0"))$escape$,
  $escape$python$escape$,
